#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, K; scanf("%d %d", &N, &K);
        long long cnt[31] = {0};
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            for(int b=0;b<31;b++) if(x & (1<<b)) cnt[b]++;
        }
        long long ans = 0;
        for(int b=0;b<31;b++) if(cnt[b]) ans += (cnt[b] + K - 1) / K;
        printf("%lld\n", ans);
    }
    return 0;
}

